import { Link } from "react-router-dom";

function PostCard({ post }) {

  return (

    <div className="post-card">

      <img
        src={post.image}
        alt={post.title}
      />

      <div className="post-content">

        <span className="tag">
          Technology
        </span>

        <h3>{post.title}</h3>

        <p>{post.content}</p>

        <div className="post-footer">

          <span>
            👤 {post.author}
          </span>

          <span>
            ❤️ {post.likes}
          </span>

          <span>
            💬 {post.comments}
          </span>

        </div>

        <Link
          className="read-btn"
          to={`/post/${post.id}`}
        >
          Read More
        </Link>

      </div>

    </div>

  );
}

export default PostCard;
